```class Solution {
public:
    int minSteps(string s, string t) {
        int count[26] = {0};
        for (char c : s) count[c - 'a']++;
        for (char c : t) count[c - 'a']--;
        int steps = 0;
        for (int i = 0; i < 26; i++) {
            steps += abs(count[i]);
        }
        return steps / 2;
    }
};```
